// Uses two binary heaps (max‑heap and min‑heap) and processes T test cases.
#include <stdio.h>
#include <stdlib.h>

// ---------- Max‑heap (stores lower part) ----------
typedef struct {
    int *data;
    int size;
    int capacity;
} MaxHeap;

MaxHeap* maxHeapCreate(int cap) {
    MaxHeap *h = (MaxHeap*)malloc(sizeof(MaxHeap));
    h->data = (int*)malloc(sizeof(int)*(cap+1)); // 1‑based index
    h->size = 0;
    h->capacity = cap;
    return h;
}

void maxHeapPush(MaxHeap *h, int val) {
    int i = ++h->size;
    while (i > 1 && h->data[i/2] < val) {
        h->data[i] = h->data[i/2];
        i /= 2;
    }
    h->data[i] = val;
}

int maxHeapTop(MaxHeap *h) { return h->data[1]; }

int maxHeapPop(MaxHeap *h) {
    int ret = h->data[1];
    int x = h->data[h->size--];
    int i = 1;
    while (i*2 <= h->size) {
        int child = i*2;
        if (child+1 <= h->size && h->data[child+1] > h->data[child]) child++;
        if (h->data[child] <= x) break;
        h->data[i] = h->data[child];
        i = child;
    }
    h->data[i] = x;
    return ret;
}

// ---------- Min‑heap (stores top part) ----------
typedef struct {
    int *data;
    int size;
    int capacity;
} MinHeap;

MinHeap* minHeapCreate(int cap) {
    MinHeap *h = (MinHeap*)malloc(sizeof(MinHeap));
    h->data = (int*)malloc(sizeof(int)*(cap+1));
    h->size = 0;
    h->capacity = cap;
    return h;
}

void minHeapPush(MinHeap *h, int val) {
    int i = ++h->size;
    while (i > 1 && h->data[i/2] > val) {
        h->data[i] = h->data[i/2];
        i /= 2;
    }
    h->data[i] = val;
}

int minHeapTop(MinHeap *h) { return h->data[1]; }

int minHeapPop(MinHeap *h) {
    int ret = h->data[1];
    int x = h->data[h->size--];
    int i = 1;
    while (i*2 <= h->size) {
        int child = i*2;
        if (child+1 <= h->size && h->data[child+1] < h->data[child]) child++;
        if (h->data[child] >= x) break;
        h->data[i] = h->data[child];
        i = child;
    }
    h->data[i] = x;
    return ret;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        // allocate enough capacity for all inserts in this test case
        MaxHeap *low = maxHeapCreate(N);
        MinHeap *high = minHeapCreate(N);
        int total = 0;
        for (int i = 0; i < N; ++i) {
            int op; scanf("%d", &op);
            if (op == 1) {
                int x; scanf("%d", &x);
                total++;
                maxHeapPush(low, x);
                // ensure ordering property
                if (high->size > 0 && maxHeapTop(low) > minHeapTop(high)) {
                    int a = maxHeapPop(low);
                    int b = minHeapPop(high);
                    maxHeapPush(low, b);
                    minHeapPush(high, a);
                }
                // rebalance sizes to floor(total/3)
                int need = total / 3;
                while (high->size < need) {
                    int move = maxHeapPop(low);
                    minHeapPush(high, move);
                }
                while (high->size > need) {
                    int move = minHeapPop(high);
                    maxHeapPush(low, move);
                }
            } else { // query
                if (high->size == 0) {
                    printf("No reviews yet\n");
                } else {
                    printf("%d\n", minHeapTop(high));
                }
            }
        }
        free(low->data); free(low);
        free(high->data); free(high);
    }
    return 0;
}

