#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        priority_queue<int> low; // max‑heap
        priority_queue<int, vector<int>, greater<int>> high; // min‑heap
        int total=0;
        for(int i=0;i<N;++i){
            int op; cin>>op;
            if(op==1){
                int x; cin>>x; ++total;
                low.push(x);
                if(!high.empty() && low.top()>high.top()){
                    int a=low.top(); low.pop();
                    int b=high.top(); high.pop();
                    low.push(b);
                    high.push(a);
                }
                int need=total/3;
                while((int)high.size()<need){
                    high.push(low.top()); low.pop();
                }
                while((int)high.size()>need){
                    low.push(high.top()); high.pop();
                }
            }else{ // query
                if(high.empty()) cout<<"No reviews yet\n";
                else cout<<high.top()<<"\n";
            }
        }
    }
    return 0;
}

